import { parseAcceptanceCriteria } from './src/lib/ac-parser.ts';
import { performScopeAssessment, formatScopeAssessment, convertSettingsToConfig } from './src/lib/scope/index.ts';
import { getSettings } from './src/lib/settings.ts';

const issueBody = \`## Acceptance Criteria

- [ ] At minimum 1 integration test exists that exercises runCommand → phase-executor → result collection without fully mocking the execution layer
- [ ] Phase retry behavior (success after retry, failure after max retries) has test coverage — either in run.test.ts or phase-executor.test.ts
- [ ] Timeout handling (abort controller fires, phase result records timeout) has test coverage
- [ ] Existing 2,254-line unit test suite continues to pass (no removal, only additions)\`;
const issueTitle = 'run.test.ts over-mocking limits integration confidence';

(async () => {
  const settings = await getSettings();
  const config = convertSettingsToConfig(settings.scopeAssessment);
  const criteria = parseAcceptanceCriteria(issueBody);
  const assessment = performScopeAssessment(criteria, issueBody, issueTitle, config);
  console.log(formatScopeAssessment(assessment));
})();
" 2>&1

