  1→/**
  2→ * Phase execution engine for workflow orchestration.
  3→ *
  4→ * Handles executing individual phases via an AgentDriver interface,
  5→ * including cold-start retry logic and MCP fallback strategies.
  6→ *
  7→ * The SDK import has been moved to ClaudeCodeDriver — this module
  8→ * is agent-agnostic.
  9→ */
 10→
 11→import chalk from "chalk";
 12→import { execSync } from "child_process";
 13→import { ShutdownManager } from "../shutdown.js";
 14→import { PhaseSpinner } from "../phase-spinner.js";
 15→import { Phase, ExecutionConfig, PhaseResult, QaVerdict } from "./types.js";
 16→import { readAgentsMd } from "../agents-md.js";
 17→import { getDriver } from "./drivers/index.js";
 18→import type { AgentDriver, AgentExecutionConfig } from "./drivers/index.js";
 19→
 20→/**
 21→ * Natural language prompts for each phase.
 22→ * Claude Code invokes the corresponding skills via natural language.
 23→ */
 24→const PHASE_PROMPTS: Record<Phase, string> = {
 25→  spec: "Review GitHub issue #{issue} and create an implementation plan with verification criteria. Run the /spec {issue} workflow.",
 26→  "security-review":
 27→    "Perform a deep security analysis for GitHub issue #{issue} focusing on auth, permissions, and sensitive operations. Run the /security-review {issue} workflow.",
 28→  testgen:
 29→    "Generate test stubs for GitHub issue #{issue} based on the specification. Run the /testgen {issue} workflow.",
 30→  exec: "Implement the feature for GitHub issue #{issue} following the spec. Run the /exec {issue} workflow.",
 31→  test: "Execute structured browser-based testing for GitHub issue #{issue}. Run the /test {issue} workflow.",
 32→  verify:
 33→    "Verify the implementation for GitHub issue #{issue} by running commands and capturing output. Run the /verify {issue} workflow.",
 34→  qa: "Review the implementation for GitHub issue #{issue} against acceptance criteria. Run the /qa {issue} workflow.",
 35→  loop: "Parse test/QA findings for GitHub issue #{issue} and iterate until quality gates pass. Run the /loop {issue} workflow.",
 36→  merger:
 37→    "Integrate and merge completed worktrees for GitHub issue #{issue}. Run the /merger {issue} workflow.",
 38→};
 39→
 40→/**
 41→ * Self-contained prompts for non-Claude agents (Aider, Codex, etc.).
 42→ * These agents don't have a skill system, so prompts must include
 43→ * full instructions rather than skill invocations.
 44→ */
 45→const AIDER_PHASE_PROMPTS: Record<Phase, string> = {
 46→  spec: `Read GitHub issue #{issue} using 'gh issue view #{issue}'.
 47→Create a spec comment on the issue with:
 48→1. Implementation plan
 49→2. Acceptance criteria as a checklist
 50→3. Risk assessment
 51→Post the comment using 'gh issue comment #{issue} --body "<comment>"'.`,
 52→  "security-review": `Perform a security review for GitHub issue #{issue}.
 53→Read the issue with 'gh issue view #{issue}'.
 54→Check for auth, permissions, injection, and sensitive data issues.
 55→Post findings as a comment on the issue.`,
 56→  testgen: `Generate test stubs for GitHub issue #{issue}.
 57→Read the spec comments on the issue with 'gh issue view #{issue} --comments'.
 58→Create test files with describe/it blocks covering the acceptance criteria.
 59→Use the project's existing test framework.`,
 60→  exec: `Implement the feature described in GitHub issue #{issue}.
 61→Read the issue and any spec comments with 'gh issue view #{issue} --comments'.
 62→Follow the implementation plan from the spec.
 63→Write tests for new functionality.
 64→Ensure the build passes with 'npm test' and 'npm run build'.`,
 65→  test: `Test the implementation for GitHub issue #{issue}.
 66→Run 'npm test' and verify all tests pass.
 67→Check for edge cases and error handling.`,
 68→  verify: `Verify the implementation for GitHub issue #{issue}.
 69→Run relevant commands and capture their output for review.`,
 70→  qa: `Review the changes for GitHub issue #{issue}.
 71→Run 'npm test' and 'npm run build' to verify everything works.
 72→Check each acceptance criterion from the issue comments.
 73→Output a verdict: READY_FOR_MERGE, AC_MET_BUT_NOT_A_PLUS, or AC_NOT_MET
 74→with format "### Verdict: <VERDICT>" followed by an explanation.`,
 75→  loop: `Review test and QA findings for GitHub issue #{issue}.
 76→Fix any issues identified in the QA feedback.
 77→Re-run 'npm test' and 'npm run build' until all quality gates pass.`,
 78→  merger: `Integrate and merge completed worktrees for GitHub issue #{issue}.
 79→Ensure all branches are up to date and merge cleanly.`,
 80→};
 81→
 82→/**
 83→ * Phases that require worktree isolation.
 84→ * Only `spec` runs in the main repo (planning-only, no file changes).
 85→ * All other phases must run in the worktree because:
 86→ * 1. They need to read/modify the worktree code
 87→ * 2. Resuming a session created in a different cwd crashes the SDK
 88→ */
 89→const ISOLATED_PHASES: Phase[] = [
 90→  "exec",
 91→  "security-review",
 92→  "testgen",
 93→  "test",
 94→  "qa",
 95→  "loop",
 96→];
 97→
 98→/**
 99→ * Cold-start retry threshold in seconds.
100→ * Failures under this duration are likely Claude Code subprocess initialization
101→ * issues rather than genuine phase failures (based on empirical data: cold-start
102→ * failures consistently complete in 15-39s vs 150-310s for real work).
103→ */
104→const COLD_START_THRESHOLD_SECONDS = 60;
105→const COLD_START_MAX_RETRIES = 2;
106→
107→/**
108→ * Spec-specific retry configuration.
109→ * Spec failures have a higher failure rate (~8.6%) than other phases due to
110→ * transient GitHub API issues and rate limits. One extra retry with backoff
111→ * recovers most of these without user intervention.
112→ */
113→/** @internal Exported for testing only */
114→export const SPEC_RETRY_BACKOFF_MS = 5000;
115→/** @internal Exported for testing only */
116→export const SPEC_EXTRA_RETRIES = 1;
117→
118→export function parseQaVerdict(output: string): QaVerdict | null {
119→  if (!output) return null;
120→
121→  // Match various verdict formats:
122→  // - "### Verdict: X" (markdown header)
123→  // - "**Verdict:** X" (bold label with colon inside)
124→  // - "**Verdict:** **X**" (bold label and bold value)
125→  // - "Verdict: X" (plain)
126→  // Case insensitive, handles optional markdown formatting
127→  const verdictMatch = output.match(
128→    /(?:###?\s*)?(?:\*\*)?Verdict:?\*?\*?\s*\*?\*?\s*(READY_FOR_MERGE|AC_MET_BUT_NOT_A_PLUS|AC_NOT_MET|NEEDS_VERIFICATION)\*?\*?/i,
129→  );
130→
131→  if (!verdictMatch) return null;
132→
133→  // Normalize to uppercase with underscores
134→  const verdict = verdictMatch[1].toUpperCase().replace(/-/g, "_") as QaVerdict;
135→  return verdict;
136→}
137→
138→/**
139→ * Format duration in human-readable format
140→ */
141→export function formatDuration(seconds: number): string {
142→  if (seconds < 60) {
143→    return `${seconds.toFixed(1)}s`;
144→  }
145→  const mins = Math.floor(seconds / 60);
146→  const secs = seconds % 60;
147→  return `${mins}m ${secs.toFixed(0)}s`;
148→}
149→
150→/**
151→ * Get the prompt for a phase with the issue number substituted.
152→ * Selects self-contained prompts for non-Claude agents.
153→ * Includes AGENTS.md content as context so non-Claude agents
154→ * receive project conventions and workflow instructions.
155→ *
156→ * @internal Exported for testing only
157→ */
158→export async function getPhasePrompt(
159→  phase: Phase,
160→  issueNumber: number,
161→  agent?: string,
162→): Promise<string> {
163→  const prompts =
164→    agent && agent !== "claude-code" ? AIDER_PHASE_PROMPTS : PHASE_PROMPTS;
165→  const basePrompt = prompts[phase].replace(/\{issue\}/g, String(issueNumber));
166→
167→  // Include AGENTS.md content in the prompt context for non-Claude agent compatibility.
168→  // Claude reads CLAUDE.md natively, but other agents (Aider, Codex, Gemini CLI)
169→  // rely on AGENTS.md for project context.
170→  const agentsMd = await readAgentsMd();
171→  if (agentsMd) {
172→    return `Project context (from AGENTS.md):\n\n${agentsMd}\n\n---\n\n${basePrompt}`;
173→  }
174→
175→  return basePrompt;
176→}
177→
178→/**
179→ * Execute a single phase for an issue using the configured AgentDriver.
180→ */
181→async function executePhase(
182→  issueNumber: number,
183→  phase: Phase,
184→  config: ExecutionConfig,
185→  sessionId?: string,
186→  worktreePath?: string,
187→  shutdownManager?: ShutdownManager,
188→  spinner?: PhaseSpinner,
189→): Promise<PhaseResult & { sessionId?: string }> {
190→  const startTime = Date.now();
191→
192→  const prompt = await getPhasePrompt(phase, issueNumber, config.agent);
193→
194→  if (config.dryRun) {
195→    // Dry run - show the prompt that would be sent, then return
196→    if (config.verbose) {
197→      console.log(chalk.gray(`    Would execute: /${phase} ${issueNumber}`));
198→      console.log(chalk.gray(`    Prompt: ${prompt}`));
199→    }
200→    return {
201→      phase,
202→      success: true,
203→      durationSeconds: 0,
204→      output: prompt,
205→    };
206→  }
207→
208→  if (config.verbose) {
209→    console.log(chalk.gray(`    Prompt: ${prompt}`));
210→    if (worktreePath && ISOLATED_PHASES.includes(phase)) {
211→      console.log(chalk.gray(`    Worktree: ${worktreePath}`));
212→    }
213→  }
214→
215→  // Determine working directory and environment
216→  const shouldUseWorktree = worktreePath && ISOLATED_PHASES.includes(phase);
217→  const cwd = shouldUseWorktree ? worktreePath : process.cwd();
218→
219→  // Resolve file context for file-oriented drivers (e.g., Aider --file)
220→  let files: string[] | undefined;
221→  if (config.agent && config.agent !== "claude-code") {
222→    try {
223→      const output = execSync("git diff --name-only main...HEAD", {
224→        cwd,
225→        encoding: "utf-8",
226→        stdio: ["pipe", "pipe", "pipe"],
227→      }).trim();
228→      if (output) {
229→        files = output.split("\n").filter(Boolean);
230→      }
231→    } catch {
232→      // No changed files or git error — proceed without file context
233→    }
234→  }
235→
236→  // Check if shutdown is in progress
237→  if (shutdownManager?.shuttingDown) {
238→    return {
239→      phase,
240→      success: false,
241→      durationSeconds: 0,
242→      error: "Shutdown in progress",
243→    };
244→  }
245→
246→  // Create abort controller for timeout
247→  const abortController = new AbortController();
248→  const timeoutId = setTimeout(() => {
249→    abortController.abort();
250→  }, config.phaseTimeout * 1000);
251→
252→  // Register abort controller with shutdown manager for graceful shutdown
253→  // Uses add/remove to support concurrent phase execution (#404)
254→  if (shutdownManager) {
255→    shutdownManager.addAbortController(abortController);
256→  }
257→
258→  // Build environment with worktree isolation variables
259→  const env: Record<string, string> = {
260→    ...process.env,
261→    CLAUDE_HOOKS_SMART_TESTS: config.noSmartTests ? "false" : "true",
262→  };
263→
264→  // Set worktree isolation environment variables
265→  if (shouldUseWorktree) {
266→    env.SEQUANT_WORKTREE = worktreePath;
267→    env.SEQUANT_ISSUE = String(issueNumber);
268→  }
269→
270→  // Set orchestration context for skills to detect they're part of a workflow
271→  // Skills can check these to skip redundant pre-flight checks
272→  env.SEQUANT_ORCHESTRATOR = "sequant-run";
273→  env.SEQUANT_PHASE = phase;
274→
275→  // Propagate issue type for skills to adapt behavior (e.g., lighter QA for docs)
276→  if (config.issueType) {
277→    env.SEQUANT_ISSUE_TYPE = config.issueType;
278→  }
279→
280→  // Track whether we're actively streaming verbose output
281→  // Pausing spinner once per streaming session prevents truncation from rapid pause/resume cycles
282→  // (Issue #283: ora's stop() clears the current line, which can truncate output when
283→  // pause/resume is called for every chunk in rapid succession)
284→  let verboseStreamingActive = false;
285→
286→  // Safety: never resume a session when worktree isolation is active.
287→  // Even if THIS phase doesn't use the worktree, a previous phase may have
288→  // created the session there. Resuming from a different cwd crashes the SDK
289→  // (exit code 1). ISOLATED_PHASES prevents this by design, but this guard
290→  // catches edge cases (e.g. a new phase added without updating ISOLATED_PHASES).
291→  const canResume = sessionId && !worktreePath;
292→
293→  // Build AgentExecutionConfig for the driver
294→  const agentConfig: AgentExecutionConfig = {
295→    cwd,
296→    env,
297→    abortSignal: abortController.signal,
298→    phaseTimeout: config.phaseTimeout,
299→    verbose: config.verbose,
300→    mcp: config.mcp,
301→    sessionId: canResume ? sessionId : undefined,
302→    files,
303→    onOutput: config.verbose
304→      ? (text: string) => {
305→          if (!verboseStreamingActive) {
306→            spinner?.pause();
307→            verboseStreamingActive = true;
308→          }
309→          process.stdout.write(chalk.gray(text));
310→        }
311→      : undefined,
312→    onStderr: config.verbose
313→      ? (data: string) => {
314→          if (!verboseStreamingActive) {
315→            spinner?.pause();
316→            verboseStreamingActive = true;
317→          }
318→          process.stderr.write(chalk.red(data));
319→        }
320→      : undefined,
321→  };
322→
323→  // Resolve driver from config or default
324→  const driver: AgentDriver = getDriver(config.agent, {
325→    aiderSettings: config.aiderSettings,
326→  });
327→
328→  const agentResult = await driver.executePhase(prompt, agentConfig);
329→
330→  // Resume spinner after execution completes (if we paused it)
331→  if (verboseStreamingActive) {
332→    spinner?.resume();
333→  }
334→
335→  clearTimeout(timeoutId);
336→
337→  // Remove this specific abort controller from shutdown manager
338→  if (shutdownManager) {
339→    shutdownManager.removeAbortController(abortController);
340→  }
341→
342→  const durationSeconds = (Date.now() - startTime) / 1000;
343→
344→  // Map AgentPhaseResult to PhaseResult
345→  const tails = {
346→    stderrTail: agentResult.stderrTail,
347→    stdoutTail: agentResult.stdoutTail,
348→    exitCode: agentResult.exitCode,
349→  };
350→
351→  if (agentResult.success) {
352→    // For QA phase, check the verdict to determine actual success
353→    // Agent "success" just means the execution completed — we need to parse the verdict
354→    if (phase === "qa" && agentResult.output) {
355→      const verdict = parseQaVerdict(agentResult.output);
356→      if (
357→        verdict &&
358→        verdict !== "READY_FOR_MERGE" &&
359→        verdict !== "NEEDS_VERIFICATION"
360→      ) {
361→        return {
362→          phase,
363→          success: false,
364→          durationSeconds,
365→          error: `QA verdict: ${verdict}`,
366→          sessionId: agentResult.sessionId,
367→          output: agentResult.output,
368→          verdict,
369→          ...tails,
370→        };
371→      }
372→      return {
373→        phase,
374→        success: true,
375→        durationSeconds,
376→        sessionId: agentResult.sessionId,
377→        output: agentResult.output,
378→        verdict: verdict ?? undefined,
379→        ...tails,
380→      };
381→    }
382→
383→    return {
384→      phase,
385→      success: true,
386→      durationSeconds,
387→      sessionId: agentResult.sessionId,
388→      output: agentResult.output,
389→      ...tails,
390→    };
391→  }
392→
393→  return {
394→    phase,
395→    success: false,
396→    durationSeconds,
397→    error: agentResult.error,
398→    sessionId: agentResult.sessionId,
399→    ...tails,
400→  };
401→}
402→
403→/**
404→ * Execute a phase with automatic retry for cold-start failures and MCP fallback.
405→ *
406→ * Retry strategy:
407→ * 1. If phase fails within COLD_START_THRESHOLD_SECONDS, retry up to COLD_START_MAX_RETRIES times
408→ * 2. If still failing and MCP is enabled, retry once with MCP disabled (npx-based MCP servers
409→ *    can fail on first run due to cold-cache issues)
410→ *
411→ * The MCP fallback is safe because MCP servers are optional enhancements, not required
412→ * for core functionality.
413→ */
414→/**
415→ * @internal Exported for testing only
416→ */
417→export async function executePhaseWithRetry(
418→  issueNumber: number,
419→  phase: Phase,
420→  config: ExecutionConfig,
421→  sessionId?: string,
422→  worktreePath?: string,
423→  shutdownManager?: ShutdownManager,
424→  spinner?: PhaseSpinner,
425→  /** @internal Injected for testing — defaults to module-level executePhase */
426→  executePhaseFn: typeof executePhase = executePhase,
427→  /** @internal Injected for testing — defaults to setTimeout-based delay */
428→  delayFn: (ms: number) => Promise<void> = (ms) =>
429→    new Promise((resolve) => setTimeout(resolve, ms)),
430→): Promise<PhaseResult & { sessionId?: string }> {
431→  // Skip retry logic if explicitly disabled
432→  if (config.retry === false) {
433→    return executePhaseFn(
434→      issueNumber,
435→      phase,
436→      config,
437→      sessionId,
438→      worktreePath,
439→      shutdownManager,
440→      spinner,
441→    );
442→  }
443→
444→  let lastResult: PhaseResult & { sessionId?: string };
445→
446→  // Phase 1: Cold-start retry attempts (with MCP enabled if configured)
447→  for (let attempt = 0; attempt <= COLD_START_MAX_RETRIES; attempt++) {
448→    lastResult = await executePhaseFn(
449→      issueNumber,
450→      phase,
451→      config,
452→      sessionId,
453→      worktreePath,
454→      shutdownManager,
455→      spinner,
456→    );
457→
458→    const duration = lastResult.durationSeconds ?? 0;
459→
460→    // Success → return immediately
461→    if (lastResult.success) {
462→      return lastResult;
463→    }
464→
465→    // Genuine failure (took long enough to be real work) → skip cold-start retries.
466→    // For spec phase, break to allow Phase 3 (spec-specific retry) to run.
467→    // For other phases, return immediately — no further retries.
468→    if (duration >= COLD_START_THRESHOLD_SECONDS) {
469→      if (phase === "spec") {
470→        break;
471→      }
472→      return lastResult;
473→    }
474→
475→    // Cold-start failure detected — retry
476→    if (attempt < COLD_START_MAX_RETRIES) {
477→      if (config.verbose) {
478→        console.log(
479→          chalk.yellow(
480→            `\n    ⟳ Cold-start failure detected (${duration.toFixed(1)}s), retrying... (attempt ${attempt + 2}/${COLD_START_MAX_RETRIES + 1})`,
481→          ),
482→        );
483→      }
484→    }
485→  }
486→
487→  // Capture the original error for better diagnostics
488→  const originalError = lastResult!.error;
489→
490→  // Phase 2: MCP fallback - if MCP is enabled and we're still failing, try without MCP
491→  // This handles npx-based MCP servers that fail on first run due to cold-cache issues
492→  if (config.mcp && !lastResult!.success) {
493→    console.log(
494→      chalk.yellow(
495→        `\n    ⚠️ Phase failed with MCP enabled, retrying without MCP...`,
496→      ),
497→    );
498→
499→    // Create config copy with MCP disabled
500→    const configWithoutMcp: ExecutionConfig = {
501→      ...config,
502→      mcp: false,
503→    };
504→
505→    const retryResult = await executePhaseFn(
506→      issueNumber,
507→      phase,
508→      configWithoutMcp,
509→      sessionId,
510→      worktreePath,
511→      shutdownManager,
512→      spinner,
513→    );
514→
515→    if (retryResult.success) {
516→      console.log(
517→        chalk.green(
518→          `    ✓ Phase succeeded without MCP (MCP cold-start issue detected)`,
519→        ),
520→      );
521→      return retryResult;
522→    }
523→
524→    // Update lastResult for Phase 3 (spec retry)
525→    lastResult = retryResult;
526→
527→    // Non-spec phases: return original error after MCP fallback exhausted
528→    if (phase !== "spec") {
529→      return {
530→        ...lastResult!,
531→        error: originalError,
532→      };
533→    }
534→  }
535→
536→  // Phase 3: Spec-specific retry — spec has a higher transient failure rate
537→  // than other phases (~8.6%), so one extra retry with backoff recovers most cases.
538→  if (phase === "spec" && !lastResult!.success) {
539→    for (let i = 0; i < SPEC_EXTRA_RETRIES; i++) {
540→      console.log(
541→        chalk.yellow(
542→          `\n    ⟳ Spec phase failed, retrying with ${SPEC_RETRY_BACKOFF_MS}ms backoff... (spec retry ${i + 1}/${SPEC_EXTRA_RETRIES})`,
543→        ),
544→      );
545→
546→      await delayFn(SPEC_RETRY_BACKOFF_MS);
547→
548→      const specRetryResult = await executePhaseFn(
549→        issueNumber,
550→        phase,
551→        config,
552→        sessionId,
553→        worktreePath,
554→        shutdownManager,
555→        spinner,
556→      );
557→
558→      if (specRetryResult.success) {
559→        console.log(chalk.green(`    ✓ Spec phase succeeded on retry`));
560→        return specRetryResult;
561→      }
562→
563→      lastResult = specRetryResult;
564→    }
565→
566→    // All spec retries exhausted — return with original error for diagnostics
567→    return {
568→      ...lastResult!,
569→      error: originalError,
570→    };
571→  }
572→
573→  return lastResult!;
574→}
