  1→/**
  2→ * Integration tests for CLI version output
  3→ *
  4→ * These tests run the actual built CLI to catch version resolution bugs
  5→ * that unit tests with mocks might miss (e.g., path resolution issues).
  6→ *
  7→ * Issue #86: The getCurrentVersion() bug (returning 0.0.0) passed all unit
  8→ * tests because they mocked `fs`. We only caught it after releasing v1.5.4.
  9→ */
 10→
 11→import { execSync, ExecSyncOptionsWithStringEncoding } from "child_process";
 12→import { describe, it, expect, beforeAll } from "vitest";
 13→import { resolve, dirname } from "path";
 14→import { fileURLToPath } from "url";
 15→import { existsSync, readFileSync } from "fs";
 16→
 17→const __dirname = dirname(fileURLToPath(import.meta.url));
 18→const projectRoot = resolve(__dirname, "../..");
 19→const cliPath = resolve(projectRoot, "dist/bin/cli.js");
 20→const distExists = existsSync(resolve(projectRoot, "dist"));
 21→
 22→// Read package.json version for comparison
 23→const packageJson = JSON.parse(
 24→  readFileSync(resolve(projectRoot, "package.json"), "utf-8"),
 25→);
 26→const expectedVersion = packageJson.version;
 27→
 28→const execOptions: ExecSyncOptionsWithStringEncoding = {
 29→  cwd: projectRoot,
 30→  encoding: "utf-8",
 31→  stdio: ["pipe", "pipe", "pipe"],
 32→};
 33→
 34→describe("CLI version integration", () => {
 35→  beforeAll(() => {
 36→    // Build the project before running integration tests
 37→    // This ensures dist/ exists for the tests
 38→    execSync("npm run build", {
 39→      cwd: projectRoot,
 40→      stdio: "ignore",
 41→    });
 42→  }, 30000); // 30 second timeout for build
 43→
 44→  it("--version reports correct version from package.json", () => {
 45→    let output: string;
 46→
 47→    try {
 48→      output = execSync(`node ${cliPath} --version`, execOptions);
 49→    } catch (error) {
 50→      const execError = error as {
 51→        status: number | null;
 52→        stdout: string;
 53→        stderr: string;
 54→      };
 55→      throw new Error(
 56→        `CLI --version crashed with exit code ${execError.status}.\n` +
 57→          `stdout: ${execError.stdout}\n` +
 58→          `stderr: ${execError.stderr}`,
 59→      );
 60→    }
 61→
 62→    // Version output should match package.json exactly
 63→    expect(output.trim()).toBe(expectedVersion);
 64→
 65→    // Ensure we're not getting the fallback 0.0.0
 66→    expect(output.trim()).not.toBe("0.0.0");
 67→  });
 68→
 69→  it("status command shows correct package version", () => {
 70→    // Retry once — CI runners occasionally kill the child process via signal
 71→    // (e.g., OOM or resource pressure), producing empty stdout.
 72→    let output = "";
 73→    const maxAttempts = 2;
 74→
 75→    for (let attempt = 1; attempt <= maxAttempts; attempt++) {
 76→      try {
 77→        output = execSync(`node ${cliPath} status`, execOptions);
 78→        break;
 79→      } catch (error) {
 80→        const execError = error as {
 81→          status: number | null;
 82→          stdout: string;
 83→          stderr: string;
 84→          signal?: string;
 85→        };
 86→        output = execError.stdout || "";
 87→
 88→        // Process killed by signal (status is null) — retry if possible
 89→        if (execError.status === null) {
 90→          if (attempt < maxAttempts) continue;
 91→          throw new Error(
 92→            `CLI status killed by signal ${execError.signal || "unknown"} after ${maxAttempts} attempts.\n` +
 93→              `stdout: ${JSON.stringify(output)}\n` +
 94→              `stderr: ${execError.stderr}`,
 95→          );
 96→        }
 97→
 98→        // Non-zero exit with no stdout — crash
 99→        if (execError.status !== 0 && !output) {
100→          throw new Error(
101→            `CLI status crashed with exit code ${execError.status}.\n` +
102→              `stderr: ${execError.stderr}`,
103→          );
104→        }
105→
106→        // Non-zero exit but has stdout — use it (status may exit non-zero if not initialized)
107→        break;
108→      }
109→    }
110→
111→    // Status should include "Package version: X.X.X"
112→    expect(output).toContain(`Package version: ${expectedVersion}`);
113→
114→    // Ensure we're not getting the fallback 0.0.0
115→    expect(output).not.toContain("Package version: 0.0.0");
116→  });
117→
118→  it("-V (short version flag) reports correct version", () => {
119→    let output: string;
120→
121→    try {
122→      output = execSync(`node ${cliPath} -V`, execOptions);
123→    } catch (error) {
124→      const execError = error as {
125→        status: number | null;
126→        stdout: string;
127→        stderr: string;
128→      };
129→      throw new Error(
130→        `CLI -V crashed with exit code ${execError.status}.\n` +
131→          `stdout: ${execError.stdout}\n` +
132→          `stderr: ${execError.stderr}`,
133→      );
134→    }
135→
136→    expect(output.trim()).toBe(expectedVersion);
137→  });
138→});
