141→// This allows the main tests to build first, but provides a skip mechanism for docs
142→describe.skipIf(!distExists)("CLI version (pre-built)", () => {
143→  it("dist/ directory exists", () => {
144→    expect(distExists).toBe(true);
145→  });
146→});
