 12→describe("Parallel Execution - Integration", () => {
 13→  describe("AC-1: Default mode runs issues concurrently", () => {
 14→    it("should run issues concurrently with Promise.allSettled + p-limit", async () => {
 15→      const limit = pLimit(3);
 16→      const startTimes: number[] = [];
 17→      const completionOrder: number[] = [];
 18→
 19→      // Simulate 3 issues that each take 50ms
 20→      const issueNumbers = [100, 101, 102];
 21→      const results = await Promise.allSettled(
 22→        issueNumbers.map((num) =>
 23→          limit(async () => {
 24→            startTimes.push(Date.now());
 25→            await new Promise((resolve) => setTimeout(resolve, 50));
 26→            completionOrder.push(num);
 27→            return { issueNumber: num, success: true };
 28→          }),
 29→        ),
 30→      );
 31→
 32→      // All 3 should have started within a small window (concurrent)
 33→      const maxStartGap = Math.max(...startTimes) - Math.min(...startTimes);
 34→      expect(maxStartGap).toBeLessThan(50); // All started before first completes
 35→
 36→      // All results fulfilled
 37→      expect(results.every((r) => r.status === "fulfilled")).toBe(true);
 38→    });
 39→  });
 40→
 41→  describe("AC-2: Concurrency limit configurable", () => {
 42→    it("should limit concurrent executions to the specified value", async () => {
 43→      const limit = pLimit(2); // Max 2 concurrent
 44→      let activeConcurrent = 0;
 45→      let maxConcurrent = 0;
 46→
 47→      const issueNumbers = [100, 101, 102, 103];
 48→      await Promise.allSettled(
 49→        issueNumbers.map((num) =>
 50→          limit(async () => {
 51→            activeConcurrent++;
 52→            maxConcurrent = Math.max(maxConcurrent, activeConcurrent);
 53→            await new Promise((resolve) => setTimeout(resolve, 50));
 54→            activeConcurrent--;
 55→            return { issueNumber: num, success: true };
 56→          }),
 57→        ),
 58→      );
 59→
 60→      // At most 2 ran concurrently
 61→      expect(maxConcurrent).toBe(2);
 62→    });
 63→
 64→    it("should use default concurrency of 3", () => {
 65→      expect(DEFAULT_CONFIG.concurrency).toBe(3);
 66→    });
 67→  });
 68→
 69→  describe("AC-4: Failure isolation", () => {
 70→    it("should continue other issues when one fails", async () => {
 71→      const limit = pLimit(3);
 72→      const issueNumbers = [100, 101, 102];
 73→
 74→      const results = await Promise.allSettled(
 75→        issueNumbers.map((num) =>
 76→          limit(async () => {
 77→            if (num === 101) {
 78→              throw new Error("Issue 101 failed");
 79→            }
 80→            return {
 81→              issueNumber: num,
 82→              success: true,
 83→              phaseResults: [],
 84→              durationSeconds: 0,
 85→            } as IssueResult;
 86→          }),
 87→        ),
 88→      );
 89→
 90→      // Issue 101 rejected, others fulfilled
 91→      expect(results[0].status).toBe("fulfilled");
 92→      expect(results[1].status).toBe("rejected");
 93→      expect(results[2].status).toBe("fulfilled");
 94→    });
 95→
 96→    it("should report the correct failure in results", async () => {
 97→      const limit = pLimit(3);
 98→
 99→      const results = await Promise.allSettled(
100→        [100, 101, 102].map((num) =>
101→          limit(async () => {
102→            const success = num !== 101;
103→            return {
104→              issueNumber: num,
105→              success,
106→              phaseResults: [],
107→              durationSeconds: 1,
108→              loopTriggered: false,
109→            } as IssueResult;
110→          }),
111→        ),
112→      );
113→
114→      // All fulfilled (errors captured in result, not thrown)
115→      const fulfilled = results
116→        .filter(
117→          (r): r is PromiseFulfilledResult<IssueResult> =>
