118→export function parseQaVerdict(output: string): QaVerdict | null {
119→  if (!output) return null;
120→
121→  // Match various verdict formats:
122→  // - "### Verdict: X" (markdown header)
123→  // - "**Verdict:** X" (bold label with colon inside)
124→  // - "**Verdict:** **X**" (bold label and bold value)
125→  // - "Verdict: X" (plain)
126→  // Case insensitive, handles optional markdown formatting
127→  const verdictMatch = output.match(
128→    /(?:###?\s*)?(?:\*\*)?Verdict:?\*?\*?\s*\*?\*?\s*(READY_FOR_MERGE|AC_MET_BUT_NOT_A_PLUS|AC_NOT_MET|NEEDS_VERIFICATION)\*?\*?/i,
129→  );
130→
131→  if (!verdictMatch) return null;
132→
133→  // Normalize to uppercase with underscores
134→  const verdict = verdictMatch[1].toUpperCase().replace(/-/g, "_") as QaVerdict;
135→  return verdict;
136→}
